using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side implementation that provides shipment data directly (no HTTP calls).
/// Used during prerender and Interactive Server mode.
/// </summary>
public class ServerShipmentService : IShipmentService
{
    // In-memory seed data for demonstration. Replace with EF Core in production.
    private static readonly List<Shipment> _shipments = new()
    {
        new() { Id = 1, TrackingNumber = "TRK-20260501-001", Origin = "New York, USA", Destination = "London, UK", Status = ShipmentStatus.InTransit, ShippedDate = new DateTime(2026, 5, 20), EstimatedDelivery = new DateTime(2026, 5, 28), CustomerEmail = "alice@example.com", Description = "Electronics - 2 boxes" },
        new() { Id = 2, TrackingNumber = "TRK-20260502-002", Origin = "Shanghai, China", Destination = "Los Angeles, USA", Status = ShipmentStatus.OutForDelivery, ShippedDate = new DateTime(2026, 5, 15), EstimatedDelivery = new DateTime(2026, 5, 25), CustomerEmail = "bob@example.com", Description = "Furniture - 1 pallet" },
        new() { Id = 3, TrackingNumber = "TRK-20260503-003", Origin = "Berlin, Germany", Destination = "Tokyo, Japan", Status = ShipmentStatus.Pending, ShippedDate = new DateTime(2026, 5, 23), EstimatedDelivery = new DateTime(2026, 6, 2), CustomerEmail = "carol@example.com", Description = "Auto parts - 5 crates" },
        new() { Id = 4, TrackingNumber = "TRK-20260504-004", Origin = "São Paulo, Brazil", Destination = "Miami, USA", Status = ShipmentStatus.Delivered, ShippedDate = new DateTime(2026, 5, 10), EstimatedDelivery = new DateTime(2026, 5, 18), CustomerEmail = "dan@example.com", Description = "Textiles - 3 boxes" },
        new() { Id = 5, TrackingNumber = "TRK-20260505-005", Origin = "Sydney, Australia", Destination = "Vancouver, Canada", Status = ShipmentStatus.Delayed, ShippedDate = new DateTime(2026, 5, 12), EstimatedDelivery = new DateTime(2026, 5, 30), CustomerEmail = "eve@example.com", Description = "Medical supplies - 10 cartons" },
        new() { Id = 6, TrackingNumber = "TRK-20260506-006", Origin = "Mumbai, India", Destination = "Dubai, UAE", Status = ShipmentStatus.PickedUp, ShippedDate = new DateTime(2026, 5, 24), EstimatedDelivery = new DateTime(2026, 5, 29), CustomerEmail = "frank@example.com", Description = "Machinery - 2 containers" },
    };

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is null)
            return Task.FromResult<Shipment?>(null);

        shipment.Status = newStatus;
        return Task.FromResult<Shipment?>(shipment);
    }
}

