// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
app.MapGet("api/shipments", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()))
    .RequireAuthorization();

app.MapGet("api/shipments/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetShipmentByTrackingAsync(trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
}).RequireAuthorization();

app.MapPut("api/shipments/{id:int}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
{
    var shipment = await service.UpdateShipmentStatusAsync(id, newStatus);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
}).RequireAuthorization();

app.Run();

