@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments - Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>
<p>Manage and monitor all shipments.</p>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-secondary" @onclick="RefreshShipments">🔄 Refresh</button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match the current filter.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    @onchange="(e) => UpdateStatus(shipment.Id, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status" selected="@(status == shipment.Status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert alert-info mt-3" role="alert">@message</div>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private string message = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrWhiteSpace(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrWhiteSpace(statusFilter) || s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await RefreshShipments();
    }

    private async Task RefreshShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
        message = string.Empty;
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
            if (updated is not null)
            {
                message = $"Shipment {updated.TrackingNumber} updated to {newStatus}.";
                await RefreshShipments();
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>
<p>Enter your tracking number to check current status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="e.g. TRK-20260501-001"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                    <span> Searching...</span>
                }
                else
                {
                    <span>🔍 Track</span>
                }
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<code>@searchedTracking</code>".
        Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>

                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>

                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

            @{
                var daysRemaining = (shipment.EstimatedDelivery - DateTime.Today).Days;
            }
            @if (shipment.Status == ShipmentStatus.Delivered)
            {
                <div class="alert alert-success mt-3">✅ This shipment has been delivered.</div>
            }
            else if (shipment.Status == ShipmentStatus.Delayed)
            {
                <div class="alert alert-danger mt-3">⚠️ This shipment is delayed. Updated delivery estimate pending.</div>
            }
            else if (daysRemaining > 0)
            {
                <div class="alert alert-info mt-3">📅 Estimated @daysRemaining day(s) until delivery.</div>
            }
            else if (daysRemaining == 0)
            {
                <div class="alert alert-success mt-3">🚚 Delivery expected today!</div>
            }
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedTracking = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool isSearching;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searched = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingAsync(trackingNumber.Trim());
        searchedTracking = trackingNumber.Trim();
        searched = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

